// Heist data comes from heists.json, which is kept in sync with heists.xlsx
// automatically — edit heists.xlsx, save, and Metro reloads the app.
//
// Lock content (riddles + answers) comes from rhymes.json, generated by:
//   npm run sync-rhymes

import heistsData from './heists.json';

// ── Core exports ──────────────────────────────────────────────────────────────

/** Flat list of every active heist across all countries. */
export const LEVELS = heistsData.flatMap(c => c.levels);

/**
 * Countries grouped with their active heist levels.
 * Countries with no active heists are excluded entirely.
 */
export const COUNTRY_GROUPS = heistsData;

// ── Helpers ───────────────────────────────────────────────────────────────────

/** Sum of all lock syllable counts — the "difficulty number" shown on briefing. */
export function getHeistTotalSyllables(level) {
  return level.locks.reduce((sum, lock) => sum + lock.syllables, 0);
}

const DIFFICULTY_ORDER = ['misdemeanor', 'felony', 'most-wanted', 'public-enemy'];

/** Highest-tier difficulty among the heist's locks. */
export function getHeistDifficulty(level) {
  return level.locks.reduce((best, lock) => {
    return DIFFICULTY_ORDER.indexOf(lock.difficulty) > DIFFICULTY_ORDER.indexOf(best)
      ? lock.difficulty
      : best;
  }, 'misdemeanor');
}

/** Colour for the difficulty badge based on total syllable count. */
export function getHeistDifficultyColor(totalSyllables) {
  if (totalSyllables <= 3)  return '#27AE60'; // green
  if (totalSyllables <= 6)  return '#E8824A'; // orange
  if (totalSyllables <= 9)  return '#C0392B'; // red
  return '#9B59B6';                           // purple
}

// ── Constants ─────────────────────────────────────────────────────────────────

export const DIFFICULTY_LABELS = {
  misdemeanor:    'MISDEMEANOR',
  felony:         'FELONY',
  'most-wanted':  'MOST WANTED',
  'public-enemy': 'PUBLIC ENEMY NO. 1',
};

export const DIFFICULTY_COLORS = {
  misdemeanor:    '#27AE60',
  felony:         '#C9A84C',
  'most-wanted':  '#C0392B',
  'public-enemy': '#9B59B6',
};

export const CITIES = heistsData.map(c => c.city);
